parameters.jsCode:
const threshold = parseFloat($env.PULSE_ALERT_THRESHOLD || 6.0);
const week = new Date().toISOString().slice(0,10);
const all = $input.all().map(i=>i.json);
const thisWeek = all.filter(r=>r.week === week || !r.week);
const avg = (arr, key) => arr.length > 0 ? (arr.reduce((s,r)=>s+parseFloat(r[key]||0),0)/arr.length).toFixed(1) : null;
const avgScore = avg(thisWeek, 'score');
const avgMorale = avg(thisWeek, 'morale');
const avgAlignment = avg(thisWeek, 'alignment');
// Previous week
const prevDate = new Date(); prevDate.setDate(prevDate.getDate()-7);
const prevWeek = all.filter(r=>r.week === prevDate.toISOString().slice(0,10));
const prevScore = avg(prevWeek, 'score');
const change = prevScore !== null && avgScore !== null ? (parseFloat(avgScore)-parseFloat(prevScore)).toFixed(1) : null;
const alert = avgScore !== null && parseFloat(avgScore) < threshold;
const comments = thisWeek.map(r=>r.comment).filter(Boolean);
return [{ json: { week, respondents: thisWeek.length, avg_score: parseFloat(avgScore), avg_morale: parseFloat(avgMorale), avg_alignment: parseFloat(avgAlignment), prev_avg_score: parseFloat(prevScore), change_from_prev: change !== null ? parseFloat(change) : null, threshold, alert, comments } }];

